import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/installer-screen.Db0E_BrK.js";import{t as a}from"./chunks/launcher-screen.B4Y3DSWp.js";import{t as o}from"./chunks/macos-settings.e7FrcLCc.js";const s=JSON.parse(`{"title":"Установка Fabric на macOS","description":"Пошаговое руководство по установке Fabric на macOS.","frontmatter":{"title":"Установка Fabric на macOS","description":"Пошаговое руководство по установке Fabric на macOS.","authors":["Benonardo","ezfe","IMB11","modmuss50"],"next":false,"files":[]},"headers":[],"relativePath":"ru_ru/players/installing-fabric/macos.md","filePath":"translated/ru_ru/players/installing-fabric/macos.md","lastUpdated":1770561656000}`);var c={name:`ru_ru/players/installing-fabric/macos.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Установка Fabric на macOS <a class="header-anchor" href="#h1" aria-label="Permalink to “Установка Fabric на macOS”">​</a></h1><div class="info custom-block"><p class="custom-block-title">ТРЕБОВАНИЯ</p><p>Перед запуском файла <code>.jar</code> может потребоваться <a href="./../installing-java/macos">установить Java</a>.</p></div><h2 id="1-download-the-fabric-installer" tabindex="-1">1. Загрузка установщика Fabric <a class="header-anchor" href="#1-download-the-fabric-installer" aria-label="Permalink to “1. Загрузка установщика Fabric”">​</a></h2><p>Загрузите версию Fabric Installer в формате <code>.jar</code> с <a href="https://fabricmc.net/use/" target="_blank" rel="noreferrer">веб-сайта Fabric</a>, нажав на кнопку <code>Download installer (Universal/.JAR)</code>.</p><h2 id="2-run-the-fabric-installer" tabindex="-1">2. Запуск установщика Fabric <a class="header-anchor" href="#2-run-the-fabric-installer" aria-label="Permalink to “2. Запуск установщика Fabric”">​</a></h2><p>Перед запуском установщика закройте Minecraft и Minecraft Launcher.</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>Вы можете получить предупреждение о том, что Apple не смогла проверить файл <code>.jar</code>. Чтобы обойти это, откройте «Настройки системы» &gt; «Конфиденциальность и безопасность», затем нажмите «Открыть в любом случае». Подтвердите и введите пароль администратора, если будет предложено.</p><p><img src="/assets/players/installing-fabric/macos-settings.png" alt="Настройки системы macOS" loading="lazy"></p></div><p>После запуска установщика вы должны увидеть экран, похожий на этот:</p><p><img src="/assets/players/installing-fabric/installer-screen.png" alt="Установщик Fabric с подсвеченным «Установить»" loading="lazy"></p><p>Выберите желаемую версию Minecraft и нажмите «Установить». Убедитесь, что опция «Создать профиль» отмечена.</p><h3 id="installing-via-homebrew" tabindex="-1">Установка через Homebrew <a class="header-anchor" href="#installing-via-homebrew" aria-label="Permalink to “Установка через Homebrew”">​</a></h3><p>Если у вас уже установлен <a href="https://brew.sh" target="_blank" rel="noreferrer">Homebrew</a>, вы можете установить Fabric Installer с помощью <code>brew</code>:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">brew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> fabric-installer</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="3-finish-setup" tabindex="-1">3. Завершение настроек <a class="header-anchor" href="#3-finish-setup" aria-label="Permalink to “3. Завершение настроек”">​</a></h2><p>После завершения установки откройте Minecraft Launcher. Затем выберите профиль Fabric из раскрывающегося списка версий и нажмите «Играть».</p><p><img src="/assets/players/installing-fabric/launcher-screen.png" alt="Minecraft Launcher с выбранным профилем Fabric" loading="lazy"></p><p>Теперь вы можете добавлять моды в свою игру. См. руководство <a href="./../finding-mods">Поиск надежных модов</a> для получения доп. информации.</p><p>Если у вас возникнут проблемы, не стесняйтесь обращаться за помощью в <a href="https://discord.fabricmc.net/" target="_blank" rel="noreferrer">Fabric Discord</a> в канале <code>#player-support</code>.</p>`,18)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};